import 'bootstrap/dist/css/bootstrap.min.css';

import NavigationBar from './components/NavigationBar';
import SimpleCarousel from './components/SimpleCarousel';
import GameIFrame from './components/GameIFrame';
import VideoCard from './components/VideoCard';
import CustomButton from "./components/CustomButton";

import ScrollProgress from './components/ScrollListener';
import ScrollProgressBar from './components/ScrollProgressBar';

import React, { useState } from 'react';

function App() {

    const [scrollPercentage, setScrollPercentage] = useState(0);
  
    const handleScroll = (percentage) => {
      setScrollPercentage(percentage);
    };

    const sections = [
      { id: 'section-0', text: 'Sección 0' },
      { id: 'section-1', text: 'Sección 1' },
      { id: 'section-2', text: 'Sección 2' }
    ];

    const images = [
      { src: "./pics/first-slide.jpg", title: "Primera imagen", description: "" },
      { src: "./pics/second-slide.jpg", title: "Segunda imagen", description: "" },
      { src: "./pics/third-slide.jpg", title: "Tercera imagen", description: "" }
    ];

  return (
    <div className="App">
      <header>
        <NavigationBar sections={sections} />
      </header>

      <body>
      <ScrollProgress onScroll={handleScroll} />

        <section id='section-0' />
        <GameIFrame
          title={"Sediento"}
          embed={"./Sediento/game.html"}
          maxWidth={600} />

        <section id='section-1' />
        <SimpleCarousel images={images} />

        <section id='section-2' />
        <div className="container">
          <div className="row">
            <VideoCard
              url=".\Videos\Sparkle.mp4"
              title="Título del video"
              description="Descripción del video"
              buttonComponent={<CustomButton buttonLabel={"Ver más"} buttonUrl={"/ruta-al-video"} />}
            />
            <VideoCard
              url=".\Videos\Sparkle.mp4"
              title="Título del video"
              description="Descripción del video"
            />
            <VideoCard
              url=".\Videos\Sparkle.mp4"
              title="Título del video"
              description="Descripción del video"
              buttonComponent={<CustomButton buttonLabel={"Ver más"} buttonUrl={"/ruta-al-video"} />}
            />
          </div>
        </div>
      </body>

      <footer>
           <ScrollProgressBar scrollPercentage={scrollPercentage} />
      </footer>
    </div>
  );
}

export default App;
